import{_ as n,C as s,o as l,c,ag as i,E as a,j as o,a as t}from"./chunks/framework.BKqeivun.js";const v=JSON.parse('{"title":"Audio production","description":"","frontmatter":{},"headers":[],"relativePath":"guide/audio.md","filePath":"guide/audio.md"}'),d={name:"guide/audio.md"};function p(h,e,u,g,m,b){const r=s("SchemeImage");return l(),c("div",null,[e[0]||(e[0]=i('<h1 id="audio-production" tabindex="-1">Audio production <a class="header-anchor" href="#audio-production" aria-label="Permalink to &quot;Audio production&quot;">​</a></h1><p>The Audio room generates speech from your scripts using text-to-speech, handles uploaded voiceovers with timestamp-based splitting, supports sound effect sections, and layers background music under the voice track. Reach it via <strong>Audio</strong> on the top-chrome stage rail, or from the Script editor with <strong>Send to audio</strong> / <strong>Promote &amp; send</strong>.</p><h2 id="script-breakdown-project-setup" tabindex="-1">Script breakdown (project setup) <a class="header-anchor" href="#script-breakdown-project-setup" aria-label="Permalink to &quot;Script breakdown (project setup)&quot;">​</a></h2><p>Pick a script in Review or Final status from the header dropdown. CRAFT parses it into sections and shows you the breakdown before you commit to a voice or mode:</p>',4)),a(r,{name:"audio-sections",alt:"Script parsed into 5 sections before creating the project — pick AI Voice (TTS) or Upload mode, tune default pause, then Create"}),e[1]||(e[1]=o("p",null,[t("Toggle between "),o("strong",null,"AI Voice (TTS)"),t(" and "),o("strong",null,"Upload Recording"),t(" at the top. The numbered list below the tabs is a live preview of the parsed sections — any row tagged "),o("code",null,"scene"),t(" is a stage direction that becomes scene context rather than spoken text. Adjust the default pause slider to set the silence between sections (per-section overrides come later in the editor).")],-1)),e[2]||(e[2]=o("h2",{id:"per-section-editor-recording-re-record",tabindex:"-1"},[t("Per-section editor (recording & re-record) "),o("a",{class:"header-anchor",href:"#per-section-editor-recording-re-record","aria-label":'Permalink to "Per-section editor (recording & re-record)"'},"​")],-1)),e[3]||(e[3]=o("p",null,"Once the project exists the view flips into the 3-column editor. Every parsed beat gets its own row with a waveform, play/regenerate/upload controls, and a delay-after slider. Click any row to focus it in the right rail, where you can edit the text, attach resources, or remove the section entirely:",-1)),a(r,{name:"audio-recordings",alt:"Per-section editor — 5 TTS sections with waveforms, status chips, and per-section regenerate/upload/record buttons; focused section detail in the right rail"}),e[4]||(e[4]=i('<p>This is where you iterate. Common moves:</p><ul><li><strong>Regenerate one section</strong> — the loop-arrow icon on any row re-runs TTS with the current voice settings. Useful when a single beat comes out with bad pacing.</li><li><strong>Upload one section</strong> — replace a single beat with a recorded take without retaking the whole script. Drop a WAV/MP3 on the upload icon; it&#39;s stored lossless-first and the waveform updates in place.</li><li><strong>Strip directions</strong> — the right-rail shortcut scrubs <code>*(stage direction)*</code> markers from the focused section&#39;s text (or use <strong>Strip all directions</strong> in the left rail to do the whole project).</li><li><strong>Insert SFX between rows</strong> — hover the gap between two rows and click <strong>+</strong>; SFX rows carry an amber <code>sfx</code> chip.</li><li><strong>Tune the pause after any row</strong> — the delay-after slider in the right rail overrides the default for just this beat.</li></ul><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>Once a script and an active project are selected, the panel switches to a three-column <strong>Audio room</strong> layout:</p><ul><li><strong>Left rail</strong> — voice header (inline rename), service/RVC chip, live stats (sections / ready / pending / duration), primary actions (Generate all · Merge · Preview RVC · Strip all directions), collapsible <strong>Voice smoothing</strong> (TTS-only sliders), collapsible <strong>Background bed</strong> (upload or MusicGen tabs + volume / fade / mode), collapsible <strong>Orphaned</strong> (audio files no longer linked to a section).</li><li><strong>Centre</strong> — script title + total duration at the top, <strong>row-per-beat</strong> section list with inline mini-waveform and status chip, insert-section + delay-ms between rows, and a <strong>master timeline</strong> footer with the merged output&#39;s play button and proportional timeline.</li><li><strong>Right rail</strong> — focused section detail: text (click <strong>Edit</strong> for a textarea), any scene context callout, linked resources, and actions (Play · Regenerate · Upload · Record · Strip directions · Remove · delay-after slider).</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>A script in <strong>Review</strong> or <strong>Final</strong> status (drafts are blocked).</li><li>A voice configured in <a href="/CRAFT/guide/settings.html">Settings</a> — or selected per-project on the first creation screen.</li></ul><h2 id="two-modes" tabindex="-1">Two modes <a class="header-anchor" href="#two-modes" aria-label="Permalink to &quot;Two modes&quot;">​</a></h2><h3 id="tts-ai-voice" tabindex="-1">TTS (AI voice) <a class="header-anchor" href="#tts-ai-voice" aria-label="Permalink to &quot;TTS (AI voice)&quot;">​</a></h3><p>Generate speech from script text using one of four TTS providers:</p><table tabindex="0"><thead><tr><th>Provider</th><th>Voices</th><th>Cost</th><th>Quality</th></tr></thead><tbody><tr><td><strong>Edge TTS</strong></td><td>300+ Microsoft Neural voices</td><td>Free</td><td>Good</td></tr><tr><td><strong>ElevenLabs</strong></td><td>Premium cloned/generated voices</td><td>Paid</td><td>Excellent</td></tr><tr><td><strong>OpenAI</strong></td><td>6 voices</td><td>Paid</td><td>Very Good</td></tr><tr><td><strong>OpenedAI Speech</strong></td><td>6 voices (local GPU)</td><td>Free</td><td>Very Good</td></tr></tbody></table><p>Any carrier voice can optionally be post-processed through <strong>RVC Voice Clone</strong> to sound like your trained voice model — see <a href="#voice-cloning-rvc">Voice cloning (RVC)</a> below.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Edge TTS is the default — no API key needed. <strong>OpenedAI Speech</strong> is also free if you have a GPU. Enable GPU services via Helm (<code>gpu.enabled: true</code>) or <code>docker compose -f docker-compose.dev.yml --profile gpu up -d</code> for local dev.</p></div><h3 id="upload-recorded-voiceover" tabindex="-1">Upload (recorded voiceover) <a class="header-anchor" href="#upload-recorded-voiceover" aria-label="Permalink to &quot;Upload (recorded voiceover)&quot;">​</a></h3><ol><li>Create a project in <strong>Upload</strong> mode.</li><li>Upload a recorded voiceover (MP3, WAV, OGG, FLAC, M4A).</li><li>Set start/end timestamps (mm:ss) for each section — the fields auto-format on blur.</li><li>Click <strong>Split All</strong> — sections are extracted as lossless WAV files.</li><li>Re-upload any single section independently if you need to retake just that part.</li></ol><h2 id="creating-a-project" tabindex="-1">Creating a project <a class="header-anchor" href="#creating-a-project" aria-label="Permalink to &quot;Creating a project&quot;">​</a></h2><ol><li>Open the Audio room.</li><li>Select a script (must be Review or Final).</li><li>Choose <strong>AI Voice (TTS)</strong> or <strong>Upload</strong> mode.</li><li>If TTS: pick the service and a voice.</li><li>Click <strong>Create Project</strong>.</li></ol><p>The script is automatically parsed into sections.</p><h2 id="section-parsing" tabindex="-1">Section parsing <a class="header-anchor" href="#section-parsing" aria-label="Permalink to &quot;Section parsing&quot;">​</a></h2><p>The parser tries three strategies in order:</p><ol><li><strong>Screenplay format</strong> — detects stage directions <code>*(...)*</code> and character dialog <code>**Name:** text</code>.</li><li><strong>Structural markers</strong> — splits on <code>### headings</code>, <code>---</code> dividers, and <code>**Bold Headers**</code>.</li><li><strong>Paragraph fallback</strong> — splits on double newlines if the above produce only 1 section.</li></ol><div class="info custom-block"><p class="custom-block-title">Stage directions</p><p>Text in <code>*(stage direction)*</code> markers becomes <strong>scene context</strong> — not spoken by TTS but shown as an amber callout above the section row that can be toggled on/off with the eye icon.</p></div><h2 id="sound-effect-sections" tabindex="-1">Sound-effect sections <a class="header-anchor" href="#sound-effect-sections" aria-label="Permalink to &quot;Sound-effect sections&quot;">​</a></h2><p>Insert SFX anywhere in the timeline: hover the gap between two rows, click <strong>+</strong>, pick <strong>Sound Effect</strong>. Upload any audio file; SFX rows carry an amber <code>sfx</code> chip and the waveform tracks the imported clip.</p><p>Use SFX for transition stingers, intro/outro jingles, or ambient breaks.</p><h2 id="background-bed" tabindex="-1">Background bed <a class="header-anchor" href="#background-bed" aria-label="Permalink to &quot;Background bed&quot;">​</a></h2><p>The <strong>Background bed</strong> section in the left rail controls the ambient layer:</p><ul><li><strong>Upload</strong> — pick a file or drop it in. Configure volume, fade in/out, and mode (Loop / Trim to voice / Play once).</li><li><strong>Generate</strong> (tab, if MusicGen GPU service is running) — describe the music, set duration, generate.</li></ul><p>Settings are applied during <strong>Merge</strong>.</p><h3 id="standalone-music-generation" tabindex="-1">Standalone music generation <a class="header-anchor" href="#standalone-music-generation" aria-label="Permalink to &quot;Standalone music generation&quot;">​</a></h3><p>A dedicated <strong>Music Generator</strong> panel lives at <code>activeView: &#39;audio-music&#39;</code> (reachable from the command palette or the resource sub-nav when applicable). It creates tracks without needing a project — useful for quickly auditioning ideas.</p><h2 id="generating-audio" tabindex="-1">Generating audio <a class="header-anchor" href="#generating-audio" aria-label="Permalink to &quot;Generating audio&quot;">​</a></h2><ul><li><strong>Generate all</strong> — left-rail button, processes every pending section sequentially.</li><li><strong>Regenerate</strong> (right rail / row icon) — re-generates a single section with current voice settings.</li></ul><p>Each row shows its status: pending / generating / ready / error. Errors get an inline message plus a red border.</p><h2 id="voice-controls" tabindex="-1">Voice controls <a class="header-anchor" href="#voice-controls" aria-label="Permalink to &quot;Voice controls&quot;">​</a></h2><p>In the left rail&#39;s <strong>Voice smoothing</strong> section:</p><ul><li><strong>Speed</strong> — playback speed multiplier (Edge TTS, OpenAI, OpenedAI Speech)</li><li><strong>Stability</strong> (ElevenLabs) — lower = more expressive, higher = more consistent</li><li><strong>Similarity boost</strong> (ElevenLabs) — how closely to match the original voice</li></ul><h2 id="linking-resources" tabindex="-1">Linking resources <a class="header-anchor" href="#linking-resources" aria-label="Permalink to &quot;Linking resources&quot;">​</a></h2><p>In the right-rail section detail, click <strong>Attach</strong>. The picker shows downloaded resources from the channel library. Linked resources appear as chips on the row — useful for tracking which B-roll goes with which section when later assembling video.</p><h2 id="merging" tabindex="-1">Merging <a class="header-anchor" href="#merging" aria-label="Permalink to &quot;Merging&quot;">​</a></h2><p>Click <strong>Merge all</strong> in the left rail to combine every ready section into a single audio file:</p><ul><li>Silence gaps between sections come from each row&#39;s <code>delayAfter</code> slider.</li><li>Mixed formats (WAV + MP3) are normalised automatically.</li><li>If a background track is configured, it&#39;s layered under the voice with fade in/out.</li></ul><h3 id="merge-with-rvc" tabindex="-1">Merge with RVC <a class="header-anchor" href="#merge-with-rvc" aria-label="Permalink to &quot;Merge with RVC&quot;">​</a></h3><p>When the channel has an <strong>RVC Voice Model</strong> configured, the merge button reads <strong>Merge + RVC</strong> and a <strong>Preview RVC</strong> shortcut appears next to it — it converts just the first section so you can audition the cloned voice without a full merge.</p><p>Once merged, the master timeline footer at the bottom of the centre column shows the play button, total duration, and a <strong>Finalize &amp; create episode</strong> button that promotes the project into an Episode.</p><h2 id="voice-cloning-rvc" tabindex="-1">Voice cloning (RVC) <a class="header-anchor" href="#voice-cloning-rvc" aria-label="Permalink to &quot;Voice cloning (RVC)&quot;">​</a></h2><p>Clone your voice using RVC v2 — it post-processes <strong>any</strong> TTS carrier voice into your custom voice. RVC is not a standalone TTS service; it&#39;s an optional post-processing toggle that works with Edge TTS, ElevenLabs, OpenAI, or OpenedAI Speech. Requires the GPU profile.</p><h3 id="step-1-—-collect-voice-samples" tabindex="-1">Step 1 — Collect voice samples <a class="header-anchor" href="#step-1-—-collect-voice-samples" aria-label="Permalink to &quot;Step 1 — Collect voice samples&quot;">​</a></h3><p>Record or gather 10–50 minutes of clean audio. Avoid background music or noise; use a consistent mic and room. Supported formats: WAV, MP3, OGG, FLAC, M4A.</p><p>Open the <strong>Voice training</strong> panel (<code>activeView: &#39;audio-train&#39;</code> — reachable via command palette). Drag-and-drop your files into the upload zone; the progress bar tracks total duration.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can also record externally and upload via the Audio room&#39;s Upload mode, then export the sections as WAV files for training input.</p></div><h3 id="step-2-—-train-a-model" tabindex="-1">Step 2 — Train a model <a class="header-anchor" href="#step-2-—-train-a-model" aria-label="Permalink to &quot;Step 2 — Train a model&quot;">​</a></h3><p>Training happens outside CRAFT using free tools:</p><ul><li><strong><a href="https://github.com/IAHispano/Applio" target="_blank" rel="noreferrer">Applio</a></strong> — recommended GUI for RVC training (free, local)</li><li><strong>Google Colab notebooks</strong> — free GPU training in the cloud</li></ul><p>Use your uploaded voice samples as input. Training takes 20–60 minutes depending on settings (2000–6000 steps). The output is a <code>.pth</code> model file.</p><h3 id="step-3-—-upload-your-model" tabindex="-1">Step 3 — Upload your model <a class="header-anchor" href="#step-3-—-upload-your-model" aria-label="Permalink to &quot;Step 3 — Upload your model&quot;">​</a></h3><ol><li>In the voice-training panel, select your <code>.pth</code> file (or a <code>.zip</code> containing <code>.pth</code> + <code>.index</code>).</li><li>The model appears in the Trained Models list.</li><li>Upload multiple models for different voices or styles.</li></ol><h3 id="step-4-—-enable-rvc-on-your-channel" tabindex="-1">Step 4 — Enable RVC on your channel <a class="header-anchor" href="#step-4-—-enable-rvc-on-your-channel" aria-label="Permalink to &quot;Step 4 — Enable RVC on your channel&quot;">​</a></h3><ol><li>Open the channel-pill dropdown → <strong>Channel settings</strong>.</li><li>Under <strong>Default Voice</strong>, select any TTS service and choose a carrier voice.</li><li>Enable the <strong>RVC Voice Clone (optional)</strong> dropdown and select your trained model.</li><li>Click <strong>Save</strong>.</li></ol><p>When you create an audio project, it uses a two-stage pipeline:</p><ol><li>Your chosen TTS service generates the base speech with the carrier voice.</li><li>RVC converts the carrier audio into your cloned voice.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The carrier voice affects pacing and inflection but not the final timbre — RVC replaces the voice character entirely. Pair it with Edge TTS for a completely free pipeline, or use ElevenLabs/OpenAI for higher-quality carrier speech.</p></div><h2 id="text-preprocessing" tabindex="-1">Text preprocessing <a class="header-anchor" href="#text-preprocessing" aria-label="Permalink to &quot;Text preprocessing&quot;">​</a></h2><p>Edge TTS doesn&#39;t support SSML, so text is automatically preprocessed:</p><ul><li>Dashes become commas (natural pauses)</li><li>Ellipses become periods (longer pauses)</li><li>Units spelled out: <code>°C</code> → &quot;degrees C&quot;</li><li>Abbreviations expanded: <code>e.g.</code> → &quot;for example&quot;</li></ul>',65))])}const w=n(d,[["render",p]]);export{v as __pageData,w as default};
